// Source: https://leetcode.com/problems/minimum-size-subarray-in-infinite-array/   |   Difficulty: Medium
//
// Problem Description:
// You are given a 0-indexed array nums and an integer target.
//
// A 0-indexed array infinite_nums is generated by infinitely appending the elements of nums to itself.
//
// Return the length of the shortest subarray of the array infinite_nums with a sum equal to target. If there is no such subarray return -1.
//
// Example:
// Input: nums = [1,2,3], target = 5
// Output: 2
// Explanation: In this example infinite_nums = [1,2,3,1,2,3,1,2,...].
// The subarray in the range [1,2], has the sum equal to target = 5 and length = 2.
// It can be proven that 2 is the shortest length of a subarray with sum equal to target = 5.
//
// Constraints:
// 1 <= nums.length <= 105
// 	1 <= nums[i] <= 105
// 	1 <= target <= 109
//

int minSizeSubarray(int* nums, int numsSize, int target) {
    long long total = 0;
    for (int i = 0; i < numsSize; i++) {
        total += nums[i];
    }

    int minLength = __INT_MAX__;
    int left = 0;
    long long currentSum = 0;

    for (int right = 0; right < numsSize * 2; right++) {
        currentSum += nums[right % numsSize];

        while (currentSum > target && left <= right) {
            currentSum -= nums[left % numsSize];
            left++;
        }

        if (currentSum == target) {
            int currentLength = right - left + 1;
            if (currentLength < minLength) {
                minLength = currentLength;
            }
        }
    }

    return minLength == __INT_MAX__ ? -1 : minLength;       
}
